// ── Numeración jerárquica de ítems ─────────────────────────────────────────
function numerarItems(items) {
  let itemNum = 0;
  let subNum = 0;
  return items.map(r => {
    if (r.nivel === "subitem") {
      subNum++;
      return { ...r, _num: `${itemNum}.${subNum}` };
    } else {
      itemNum++;
      subNum = 0;
      return { ...r, _num: `${itemNum}` };
    }
  });
}

