// ── Componentes base ───────────────────────────────────────────────────────
function Inp({value,onChange,type="text",placeholder="",align="left",small=false,style:ext={}}) {
  const [focus,setFocus]=useState(false);
  return <input type={type} value={value} onChange={onChange} placeholder={placeholder}
    onFocus={()=>setFocus(true)} onBlur={()=>setFocus(false)}
    style={{background:T.bg,border:`1px solid ${focus?T.borderHi:T.border}`,color:T.text,
      padding:small?"4px 7px":"6px 10px",fontSize:small?11:12,fontFamily:T.mono,
      borderRadius:3,width:"100%",boxSizing:"border-box",outline:"none",textAlign:align,
      transition:"border-color 0.15s",...ext}}/>;
}

function Sel({value,onChange,options}) {
  return <select value={value} onChange={onChange}
    style={{background:T.bg,border:`1px solid ${T.border}`,color:T.text,padding:"5px 6px",
      fontSize:11,fontFamily:T.mono,borderRadius:3,width:"100%",cursor:"pointer",outline:"none"}}>
    {options.map(o=><option key={o}>{o}</option>)}
  </select>;
}

function Btn({onClick,children,accent,ghost=false,small=false,disabled=false,full=false}) {
  const [hov,setHov]=useState(false);
  const a=accent||T.textMid;
  return <button onClick={onClick} disabled={disabled}
    onMouseEnter={()=>setHov(true)} onMouseLeave={()=>setHov(false)}
    style={{background:ghost?(hov?a+"18":"transparent"):(hov?a:a+"e0"),
      border:`1px solid ${ghost?(hov?a+"66":T.border):a}`,
      color:ghost?(hov?a:T.textMid):"#fff",padding:small?"4px 10px":"7px 16px",
      fontSize:small?11:12,fontFamily:T.mono,borderRadius:3,cursor:disabled?"not-allowed":"pointer",
      transition:"all 0.15s",opacity:disabled?0.4:1,width:full?undefined:undefined,
      letterSpacing:"0.03em",fontWeight:500}}>
    {children}
  </button>;
}

function SectionHdr({title,accent,right}) {
  return <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:14}}>
    <div style={{display:"flex",alignItems:"center",gap:10}}>
      <div style={{width:3,height:18,background:accent,borderRadius:2}}/>
      <span style={{fontFamily:T.sans,fontWeight:700,fontSize:14,color:T.text}}>{title}</span>
    </div>
    {right}
  </div>;
}

function THead({cols,accent}) {
  return <thead><tr style={{borderTop:`2px solid ${accent}`}}>
    {cols.map((c,i)=><th key={i} style={{padding:"6px 8px",fontSize:10,letterSpacing:"0.1em",
      color:T.textDim,textAlign:typeof c==="object"?c.align||"left":"left",
      borderBottom:`1px solid ${T.border}`,background:T.panel2,fontFamily:T.sans,
      fontWeight:600,textTransform:"uppercase"}}>
      {typeof c==="object"?c.label:c}
    </th>)}
  </tr></thead>;
}

function DelBtn({onClick}) {
  const [h,setH]=useState(false);
  return <td style={{padding:"3px 6px",textAlign:"center"}}>
    <button onClick={onClick} onMouseEnter={()=>setH(true)} onMouseLeave={()=>setH(false)}
      style={{background:h?"#e6394611":"transparent",border:`1px solid ${h?"#e6394644":T.border}`,
        color:h?"#e63946":T.textDim,width:22,height:22,cursor:"pointer",borderRadius:2,
        fontSize:11,lineHeight:1,transition:"all 0.15s"}}>✕</button>
  </td>;
}

// ── Generador PDF ──────────────────────────────────────────────────────────
function generarPDF(data) {
  const {categoria,empresaCli,respCli,areaCli,sede,numCot,asunto,objeto,
    items,manoObra,equipos,aiu,iva,
    directo,valorAdmin,valorImprev,valorUtilidad,montoIVA,total,
    formaPago,validez,observaciones} = data;

  const P=PALETAS[categoria];
  const fecha=new Date().toLocaleDateString("es-CO",{day:"2-digit",month:"long",year:"numeric"}).toUpperCase();

  const tRow=(idx,desc,vr)=>`<tr>
    <td style="border:1px solid #ddd;padding:5px 8px;text-align:center;color:#666;font-size:10px;">${idx}</td>
    <td style="border:1px solid #ddd;padding:5px 8px;">${desc}</td>
    <td style="border:1px solid #ddd;padding:5px 8px;text-align:right;font-weight:600;">$ ${fmt(vr)}</td>
  </tr>`;

  let rows="";
  const itemsNum = numerarItems(items);
  itemsNum.forEach((r)=>{ 
    const esSub = r.nivel === "subitem";
    rows+=`<tr>
    <td style="border:1px solid #ddd;padding:5px 8px;text-align:center;color:#666;font-size:10px;${esSub?"padding-left:20px;":""}">${esSub?"└ ":""}${r._num}</td>
    <td style="border:1px solid #ddd;padding:5px 8px;${esSub?"color:#555;font-size:10px;padding-left:20px;":""}">${r.desc||"—"}</td>
    <td style="border:1px solid #ddd;padding:5px 8px;text-align:right;font-weight:${esSub?"500":"600"};">$ ${fmt(r.cantidad*r.pu)}</td>
  </tr>`; 
  });

  manoObra.forEach((r,i)=>{ rows+=tRow(`MO-${i+1}`,`Mano de Obra: ${r.cat||"—"}`,r.n*r.costo*r.dias); });
  equipos.forEach((r,i)=>{ rows+=tRow(`EQ-${i+1}`,`Equipo: ${r.tipo||"—"}`,r.costo*r.tiempo); });

  const sRow=(lbl,val,bold=false,hi=false)=>`<tr style="background:${hi?P.accent+"15":"transparent"}">
    <td colspan="2" style="border:1px solid #ddd;padding:${bold?"7px":"5px"} 8px;text-align:right;
      font-weight:${bold?700:500};font-size:${bold?"11px":"10px"};">${lbl}</td>
    <td style="border:1px solid #ddd;padding:${bold?"7px":"5px"} 8px;text-align:right;
      font-weight:${bold?700:600};font-size:${bold?"11px":"10px"};">$ ${fmt(val)}</td>
  </tr>`;

  const html=`<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8">
  <style>
    *{margin:0;padding:0;box-sizing:border-box;-webkit-print-color-adjust:exact!important;print-color-adjust:exact!important}
    body{font-family:Arial,Helvetica,sans-serif;font-size:10.5px;color:#1a1a1a;background:#fff}
    .page{padding:20px 30px}
    .accent-bar{height:3px;background:linear-gradient(90deg,${P.accent} 0%,${P.accentDim} 100%);margin-bottom:12px;border-radius:2px}
    .info-table{width:100%;border-collapse:collapse;margin-bottom:16px;font-size:10px}
    .info-table td{border:0.5px solid #ccc;padding:4px 8px}
    .info-table .lbl{background:#f5f5f5;font-weight:700;color:#333;white-space:nowrap;width:22%}
    .objeto-box{border-left:3px solid ${P.accent};background:#f9f9f9;padding:8px 12px;margin-bottom:16px;font-size:10px}
    .main-table{width:100%;border-collapse:collapse;margin-bottom:0;font-size:10px}
    .main-table th{background:${P.accent};color:#fff;padding:6px 8px;text-align:center;font-size:10px;letter-spacing:.05em;border:1px solid ${P.accentDim}}
    .total-row{background:${P.accent}}
    .total-row td{color:#fff;font-weight:700;font-size:12px;border:1px solid ${P.accentDim};padding:8px}
    .notes-section{margin-top:14px;display:grid;grid-template-columns:1fr 1fr;gap:10px}
    .note-box{border:0.5px solid #ccc;padding:8px 10px;border-radius:2px}
    .note-box strong{display:block;font-size:9px;color:#888;letter-spacing:.1em;margin-bottom:4px;text-transform:uppercase}
    .firma-section{margin-top:30px;display:flex;justify-content:flex-end}
    .footer{margin-top:18px;border-top:1px solid #ddd;padding-top:8px;display:flex;justify-content:space-between;font-size:8.5px;color:#aaa}
  </style></head><body><div class="page">
  <div class="accent-bar"></div>
  <table style="width:100%;border-collapse:collapse;margin-bottom:16px">
    <tr>
      <td style="width:28%"><img src="${LOGO_URL}" alt="G2" style="max-width:170px;max-height:65px;object-fit:contain"/></td>
      <td style="width:42%;text-align:center">
        <div style="font-size:13px;font-weight:700;text-align:center;line-height:1.4">
          G2 PROYECTOS & MONTAJES INDUSTRIALES S.A.S.<br>
          <span style="font-size:10px;font-weight:400;color:#555">NIT: XXX.XXX.XXX-X · Yumbo, Valle del Cauca</span>
        </div>
      </td>
      <td style="width:30%">
        <table style="width:100%;border-collapse:collapse;border:1.5px solid #1a1a1a">
          <tr><td colspan="2" style="background:${P.accent};color:#fff;font-weight:700;font-size:10px;text-align:center;padding:4px;letter-spacing:.05em">COTIZACIÓN DE SERVICIOS</td></tr>
          <tr><td style="padding:3px 6px;font-weight:700;font-size:9.5px;border:0.5px solid #ccc">No.</td><td style="padding:3px 6px;border:0.5px solid #ccc">${numCot}</td></tr>
          <tr><td style="padding:3px 6px;font-weight:700;font-size:9.5px;border:0.5px solid #ccc">Fecha</td><td style="padding:3px 6px;border:0.5px solid #ccc">${fecha}</td></tr>
          <tr><td style="padding:3px 6px;font-weight:700;font-size:9.5px;border:0.5px solid #ccc">Versión</td><td style="padding:3px 6px;border:0.5px solid #ccc">01</td></tr>
          <tr><td style="padding:3px 6px;font-weight:700;font-size:9.5px;border:0.5px solid #ccc">Página</td><td style="padding:3px 6px;border:0.5px solid #ccc">1 de 1</td></tr>
        </table>
      </td>
    </tr>
  </table>
  <table class="info-table">
    <tr><td class="lbl">EMPRESA CLIENTE</td><td>${empresaCli}</td><td class="lbl">SEDE / PLANTA</td><td>${sede}</td></tr>
    <tr><td class="lbl">RESPONSABLE CLIENTE</td><td>${respCli}</td><td class="lbl">ASUNTO</td><td>${asunto}</td></tr>
    <tr><td class="lbl">ÁREA / DEPARTAMENTO</td><td>${areaCli}</td><td class="lbl">CATEGORÍA</td><td>${P.tag}</td></tr>
  </table>
  <div class="objeto-box"><strong>Objeto / Descripción del servicio</strong>${objeto}</div>
  <table class="main-table">
    <thead><tr>
      <th style="width:7%">ÍTEM</th>
      <th style="text-align:left;width:68%">DESCRIPCIÓN DEL SERVICIO / ACTIVIDAD</th>
      <th style="width:25%">VALOR TOTAL</th>
    </tr></thead>
    <tbody>
      ${rows}
      ${sRow("SUBTOTAL COSTOS DIRECTOS",directo,true)}
      ${sRow(`Administración (${aiu.admin}%)`,valorAdmin)}
      ${sRow(`Imprevistos (${aiu.imprevistos}%)`,valorImprev)}
      ${sRow(`Utilidad (${aiu.utilidad}%)`,valorUtilidad)}
      ${iva.activo?sRow(`IVA sobre Utilidad (${iva.pct}%)`,montoIVA):""}
    </tbody>
    <tfoot><tr class="total-row">
      <td colspan="2" style="text-align:right">VALOR TOTAL DEL PRESUPUESTO</td>
      <td style="text-align:right">$ ${fmt(total)}</td>
    </tr></tfoot>
  </table>
  <div class="notes-section">
    <div class="note-box"><strong>Forma de pago</strong>${formaPago||"50% anticipo · 50% a entrega de obra"}</div>
    <div class="note-box"><strong>Validez de la oferta</strong>${validez||"30 días calendario"}</div>
    ${observaciones?`<div class="note-box" style="grid-column:1/-1"><strong>Observaciones</strong>${observaciones}</div>`:""}
  </div>
  <div class="firma-section">
    <div style="text-align:center;min-width:220px">
      <div style="border-top:1.5px solid #1a1a1a;margin-bottom:4px;width:100%"></div>
      <div style="font-weight:700;font-size:11px;margin-bottom:2px">LINA VANESSA PINZÓN DUQUE</div>
      <div style="font-size:10px;color:#555">Gerente & Representante Legal</div>
      <div style="margin-top:6px;font-size:9px;color:#777;line-height:1.6">
        Cel: +(57) 322 690 8186<br>g2proyectosymontajes@hotmail.com<br>Yumbo · Valle del Cauca · Colombia
      </div>
    </div>
  </div>
  <div class="footer">
    <span>G2 Proyectos & Montajes Industriales S.A.S. — ${fecha}</span>
    <span>Cotización No. ${numCot}</span>
  </div>
  </div></body></html>`;

  const blob=new Blob([html],{type:"text/html;charset=utf-8"});
  const url=URL.createObjectURL(blob);
  const a=document.createElement("a");
  a.href=url; a.download=`Cotizacion_${numCot||"G2"}.html`; a.click();
  URL.revokeObjectURL(url);
}

// ══════════════════════════════════════════════════════════════════════════
// PANEL DE HISTORIAL
// ══════════════════════════════════════════════════════════════════════════
function HistorialPanel({historial,onCargar,onEliminar,onNuevo,accentColor}) {
  const [confirm,setConfirm]=useState(null);

  if(historial.length===0) return (
    <div style={{padding:"40px 20px",textAlign:"center",color:T.textDim}}>
      <div style={{fontSize:32,marginBottom:12,opacity:0.3}}>📂</div>
      <div style={{fontFamily:T.sans,fontSize:14,marginBottom:6}}>Sin cotizaciones guardadas</div>
      <div style={{fontSize:11,marginBottom:20}}>Las cotizaciones guardadas aparecerán aquí</div>
      <Btn onClick={onNuevo} accent={accentColor} ghost>+ Nueva cotización</Btn>
    </div>
  );

  return (
    <div>
      <div style={{padding:"14px 20px",display:"flex",justifyContent:"space-between",alignItems:"center",
        borderBottom:`1px solid ${T.border}`}}>
        <span style={{fontFamily:T.sans,fontWeight:700,fontSize:13,color:T.text}}>
          COTIZACIONES GUARDADAS ({historial.length})
        </span>
        <Btn onClick={onNuevo} accent={accentColor} ghost small>+ Nueva</Btn>
      </div>
      <div style={{overflowY:"auto",maxHeight:"calc(100vh - 180px)"}}>
        {[...historial].reverse().map(cot=>{
          const P2=PALETAS[cot.cat||"civil"];
          const fecha=new Date(cot.savedAt||Date.now()).toLocaleDateString("es-CO",
            {day:"2-digit",month:"short",year:"numeric"});
          return (
            <div key={cot.savedId} style={{padding:"14px 20px",borderBottom:`1px solid ${T.border}`,
              cursor:"pointer",transition:"background 0.15s"}}
              onMouseEnter={e=>e.currentTarget.style.background=T.panel2}
              onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
              
              {/* Fila top: badge tipo + número */}
              <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:6}}>
                <span style={{background:P2.accent+"22",border:`1px solid ${P2.accent}44`,color:P2.accent,
                  fontSize:9,padding:"2px 7px",borderRadius:2,fontFamily:T.mono,letterSpacing:"0.08em"}}>
                  {P2.icon} {P2.tag}
                </span>
                <span style={{fontFamily:T.mono,fontWeight:600,fontSize:12,color:T.text}}>
                  {cot.numCot||"Sin número"}
                </span>
              </div>
              {/* Cliente */}
              <div style={{fontFamily:T.sans,fontSize:12,color:T.textMid,marginBottom:4,
                whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>
                {cot.empresaCli||"Sin cliente"}
              </div>
              {/* Fecha + total */}
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                <span style={{fontSize:10,color:T.textDim,fontFamily:T.mono}}>{fecha}</span>
                <span style={{fontFamily:T.sans,fontWeight:700,fontSize:13,color:P2.accent}}>
                  $ {fmt(cot._total||0)}
                </span>
              </div>
              {/* Acciones */}
              <div style={{display:"flex",gap:6,marginTop:10}}>
                <Btn onClick={()=>onCargar(cot)} accent={P2.accent} ghost small>✏ Editar</Btn>
                {confirm===cot.savedId
                  ? <>
                      <Btn onClick={()=>{onEliminar(cot.savedId);setConfirm(null);}} accent="#e63946" small>Confirmar</Btn>
                      <Btn onClick={()=>setConfirm(null)} ghost small>Cancelar</Btn>
                    </>
                  : <Btn onClick={()=>setConfirm(cot.savedId)} ghost small>🗑</Btn>
                }
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

