               <textarea value={observaciones} onChange={e=>set("observaciones",e.target.value)} rows={2}
                placeholder="Condiciones especiales, exclusiones..." style={{background:T.bg,border:`1px solid ${T.border}`,color:T.text,padding:"8px 10px",fontSize:12,fontFamily:T.mono,borderRadius:3,width:"100%",boxSizing:"border-box",outline:"none",resize:"vertical"}}/>
